using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using System.ComponentModel.DataAnnotations;

namespace TicketClassifier.Models;

public class TicketRequest
{
    [Required]
    public string Subject { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [Range(1, 3)]
    public int Priority { get; set; }
}

public class TicketClassificationResult
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> ConfidenceScores { get; set; } = new();
}

public class EvaluationResult
{
    public float MacroAccuracy { get; set; }
    public float MicroAccuracy { get; set; }
    public float LogLoss { get; set; }
    public float LogLossReduction { get; set; }
    public List<CategoryMetric> PerCategoryMetrics { get; set; } = [];
}

public class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelService
{
    private readonly MLContext _mlContext;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationResult _evaluationResult;
    private readonly string[] _categoryLabels;

    public TicketModelService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);
        var (model, labels, evaluation) = TrainAndEvaluate(dataPath);
        _categoryLabels = labels;
        _evaluationResult = evaluation;
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(model);
    }

    private (ITransformer model, string[] labels, EvaluationResult evaluation) TrainAndEvaluate(string dataPath)
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.3, seed: 42);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Train on full dataset (small dataset — split evaluation is indicative only)
        var model = pipeline.Fit(data);

        var testPredictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(testPredictions);

        // Extract label names from the key column
        var labelColumn = data.Schema["Label"];
        var trainModel = pipeline.Fit(split.TrainSet);
        var fullPredictions = trainModel.Transform(split.TestSet);
        var schema = fullPredictions.Schema;

        VBuffer<ReadOnlyMemory<char>> slotNames = default;
        schema["Score"].GetSlotNames(ref slotNames);
        var labels = slotNames.DenseValues().Select(s => s.ToString()).ToArray();

        var perCategory = new List<CategoryMetric>();
        if (metrics.PerClassLogLoss != null)
        {
            for (int i = 0; i < labels.Length; i++)
            {
                perCategory.Add(new CategoryMetric
                {
                    Category = labels[i],
                    Precision = i < metrics.PerClassLogLoss.Count ? 1.0 - metrics.PerClassLogLoss[i] : 0,
                    Recall = 0,
                    F1Score = 0
                });
            }
        }

        // Compute per-class precision/recall/F1 from the confusion matrix
        var confusionMatrix = metrics.ConfusionMatrix;
        perCategory.Clear();
        for (int i = 0; i < labels.Length; i++)
        {
            var counts = confusionMatrix.GetFormattedConfusionTable()
                is not null ? confusionMatrix.Counts : null;

            double tp = 0, fp = 0, fn = 0;
            if (counts != null)
            {
                for (int j = 0; j < labels.Length; j++)
                {
                    if (i == j) tp = counts[i][j];
                    else
                    {
                        fp += counts[j][i]; // predicted i but actual j
                        fn += counts[i][j]; // actual i but predicted j
                    }
                }
            }

            double precision = tp + fp > 0 ? tp / (tp + fp) : 0;
            double recall = tp + fn > 0 ? tp / (tp + fn) : 0;
            double f1 = precision + recall > 0 ? 2 * precision * recall / (precision + recall) : 0;

            perCategory.Add(new CategoryMetric
            {
                Category = labels[i],
                Precision = Math.Round(precision, 4),
                Recall = Math.Round(recall, 4),
                F1Score = Math.Round(f1, 4)
            });
        }

        var evaluation = new EvaluationResult
        {
            MacroAccuracy = (float)Math.Round(metrics.MacroAccuracy, 4),
            MicroAccuracy = (float)Math.Round(metrics.MicroAccuracy, 4),
            LogLoss = (float)Math.Round(metrics.LogLoss, 4),
            LogLossReduction = (float)Math.Round(metrics.LogLossReduction, 4),
            PerCategoryMetrics = perCategory
        };

        return (model, labels, evaluation);
    }

    public TicketClassificationResult Predict(TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(input);

        var confidenceScores = new Dictionary<string, float>();
        for (int i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
        {
            confidenceScores[_categoryLabels[i]] = (float)Math.Round(prediction.Score[i], 4);
        }

        return new TicketClassificationResult
        {
            PredictedCategory = prediction.Category,
            ConfidenceScores = confidenceScores
        };
    }

    public EvaluationResult GetEvaluationMetrics() => _evaluationResult;
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketModelService _modelService;

    public TicketsController(TicketModelService modelService)
    {
        _modelService = modelService;
    }

    [HttpPost("classify")]
    public ActionResult<TicketClassificationResult> Classify([FromBody] TicketRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        var result = _modelService.Predict(request);
        return Ok(result);
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationResult> GetMetrics()
    {
        return Ok(_modelService.GetEvaluationMetrics());
    }
}

