1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using TicketClassifier.Models;
4. 
5. namespace TicketClassifier.Services;
6. 
7. public class TicketModelService
8. {
9.     private readonly MLContext _mlContext;
10.     private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
11.     private readonly EvaluationResult _evaluationResult;
12.     private readonly string[] _categoryLabels;
13. 
14.     public TicketModelService(string dataPath)
15.     {
16.         _mlContext = new MLContext(seed: 42);
17.         var (model, labels, evaluation) = TrainAndEvaluate(dataPath);
18.         _categoryLabels = labels;
19.         _evaluationResult = evaluation;
20.         _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(model);
21.     }
22. 
23.     private (ITransformer model, string[] labels, EvaluationResult evaluation) TrainAndEvaluate(string dataPath)
24.     {
25.         var data = _mlContext.Data.LoadFromTextFile<TicketData>(
26.             dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
27. 
28.         var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.3, seed: 42);
29. 
30.         var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
31.             .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
32.             .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
33.             .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
34.             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
35.             .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
36.             .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
37. 
38.         // Train on full dataset (small dataset — split evaluation is indicative only)
39.         var model = pipeline.Fit(data);
40. 
41.         var testPredictions = model.Transform(split.TestSet);
42.         var metrics = _mlContext.MulticlassClassification.Evaluate(testPredictions);
43. 
44.         // Extract label names from the Score column annotations
45.         var trainModel = pipeline.Fit(split.TrainSet);
46.         var fullPredictions = trainModel.Transform(split.TestSet);
47.         var schema = fullPredictions.Schema;
48. 
49.         VBuffer<ReadOnlyMemory<char>> slotNames = default;
50.         schema["Score"].Annotations.GetValue("SlotNames", ref slotNames);
51.         var labels = slotNames.DenseValues().Select(s => s.ToString()).ToArray();
52. 
53.         var perCategory = new List<CategoryMetric>();
54.         if (metrics.PerClassLogLoss != null)
55.         {
56.             for (int i = 0; i < labels.Length; i++)
57.             {
58.                 perCategory.Add(new CategoryMetric
59.                 {
60.                     Category = labels[i],
61.                     Precision = i < metrics.PerClassLogLoss.Count ? 1.0 - metrics.PerClassLogLoss[i] : 0,
62.                     Recall = 0,
63.                     F1Score = 0
64.                 });
65.             }
66.         }
67. 
68.         // Compute per-class precision/recall/F1 from the confusion matrix
69.         var confusionMatrix = metrics.ConfusionMatrix;
70.         perCategory.Clear();
71.         for (int i = 0; i < labels.Length; i++)
72.         {
73.             var counts = confusionMatrix.GetFormattedConfusionTable()
74.                 is not null ? confusionMatrix.Counts : null;
75. 
76.             double tp = 0, fp = 0, fn = 0;
77.             if (counts != null)
78.             {
79.                 for (int j = 0; j < labels.Length; j++)
80.                 {
81.                     if (i == j) tp = counts[i][j];
82.                     else
83.                     {
84.                         fp += counts[j][i]; // predicted i but actual j
85.                         fn += counts[i][j]; // actual i but predicted j
86.                     }
87.                 }
88.             }
89. 
90.             double precision = tp + fp > 0 ? tp / (tp + fp) : 0;
91.             double recall = tp + fn > 0 ? tp / (tp + fn) : 0;
92.             double f1 = precision + recall > 0 ? 2 * precision * recall / (precision + recall) : 0;
93. 
94.             perCategory.Add(new CategoryMetric
95.             {
96.                 Category = labels[i],
97.                 Precision = Math.Round(precision, 4),
98.                 Recall = Math.Round(recall, 4),
99.                 F1Score = Math.Round(f1, 4)
100.             });
101.         }
102. 
103.         var evaluation = new EvaluationResult
104.         {
105.             MacroAccuracy = (float)Math.Round(metrics.MacroAccuracy, 4),
106.             MicroAccuracy = (float)Math.Round(metrics.MicroAccuracy, 4),
107.             LogLoss = (float)Math.Round(metrics.LogLoss, 4),
108.             LogLossReduction = (float)Math.Round(metrics.LogLossReduction, 4),
109.             PerCategoryMetrics = perCategory
110.         };
111. 
112.         return (model, labels, evaluation);
113.     }
