115.     public TicketClassificationResult Predict(TicketRequest request)
116.     {
117.         var input = new TicketData
118.         {
119.             Subject = request.Subject,
120.             Description = request.Description,
121.             Priority = request.Priority
122.         };
123. 
124.         var prediction = _predictionEngine.Predict(input);
125. 
126.         var confidenceScores = new Dictionary<string, float>();
127.         for (int i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
128.         {
129.             confidenceScores[_categoryLabels[i]] = (float)Math.Round(prediction.Score[i], 4);
130.         }
131. 
132.         return new TicketClassificationResult
133.         {
134.             PredictedCategory = prediction.Category,
135.             ConfidenceScores = confidenceScores
136.         };
137.     }
