 using Microsoft.ML;
 using Microsoft.ML.Data;
 using TicketClassifier.Models;

 namespace TicketClassifier.Services;

 public class TicketModelService
 {
     private readonly MLContext _mlContext;
     private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
     private readonly EvaluationResult _evaluationResult;
     private readonly string[] _categoryLabels;

     public TicketModelService(string dataPath)
     {
         _mlContext = new MLContext(seed: 42);
         var (model, labels, evaluation) = TrainAndEvaluate(dataPath);
         _categoryLabels = labels;
         _evaluationResult = evaluation;
         _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(model);
     }

     private (ITransformer model, string[] labels, EvaluationResult evaluation) TrainAndEvaluate(string dataPath)
     {
         var data = _mlContext.Data.LoadFromTextFile<TicketData>(
             dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

         var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.3, seed: 42);

         var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
             .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
             .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
             .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
             .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
             .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

         // Train on full dataset (small dataset — split evaluation is indicative only)
         var model = pipeline.Fit(data);

         var testPredictions = model.Transform(split.TestSet);
         var metrics = _mlContext.MulticlassClassification.Evaluate(testPredictions);

         // Extract label names from the Score column annotations
         var trainModel = pipeline.Fit(split.TrainSet);
         var fullPredictions = trainModel.Transform(split.TestSet);
         var schema = fullPredictions.Schema;

         VBuffer<ReadOnlyMemory<char>> slotNames = default;
         schema["Score"].Annotations.GetValue("SlotNames", ref slotNames);
         var labels = slotNames.DenseValues().Select(s => s.ToString()).ToArray();

         var perCategory = new List<CategoryMetric>();
         if (metrics.PerClassLogLoss != null)
         {
             for (int i = 0; i < labels.Length; i++)
             {
                 perCategory.Add(new CategoryMetric
                 {
                     Category = labels[i],
                     Precision = i < metrics.PerClassLogLoss.Count ? 1.0 - metrics.PerClassLogLoss[i] : 0,
                     Recall = 0,
                     F1Score = 0
                 });
             }
         }

         // Compute per-class precision/recall/F1 from the confusion matrix
         var confusionMatrix = metrics.ConfusionMatrix;
         perCategory.Clear();
         for (int i = 0; i < labels.Length; i++)
         {
             var counts = confusionMatrix.GetFormattedConfusionTable()
                 is not null ? confusionMatrix.Counts : null;

             double tp = 0, fp = 0, fn = 0;
             if (counts != null)
             {
                 for (int j = 0; j < labels.Length; j++)
                 {
                     if (i == j) tp = counts[i][j];
                     else
                     {
                         fp += counts[j][i]; // predicted i but actual j
                         fn += counts[i][j]; // actual i but predicted j
                     }
                 }
             }

